#include <stdio.h>
int main() {
    int T, N, M, Xi, Vi;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &M);
        int count = 0;
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &Xi, &Vi);
            if (Xi > Vi) {
                count++;
            }
        }
        if (count > 0) {
            printf("1\n");
        } else {
            printf("0\n");
        }
    }
    return 0;
}

