public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int count = 0;
            for (int i = 0; i < M; i++) {
                int Xi = sc.nextInt();
                int Vi = sc.nextInt();
                if (Xi > Vi) {
                    count++;
                }
            }
            if (count > 0) {
                System.out.println("1");
            } else {
                System.out.println("0");
            }
        }
    }
}

